<?php

/**
 * PermitsTable
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 */
class PermitsTable extends Doctrine_Table
{
    /**
     * Returns an instance of this class.
     *
     * @return PermitsTable The table instance
     */
    public static function getInstance()
    {
        return Doctrine_Core::getTable('Permits');
    }



    public static function getPermitTemplates()
    {
        $templates = array();

        $permits = null;

        if(sfContext::getInstance()->getUser()->getAttribute('filter'))
        {
            $q = Doctrine_Query::create()
                ->from("SubMenus a")
                ->where("a.menu_id = ?", sfContext::getInstance()->getUser()->getAttribute('filter'));
            $stages = $q->execute();

            $stages_array = array();

            foreach($stages as $stage)
            {
                $stages_array[] = "a.applicationstage = ".$stage->getId();
            }

            $stages_query = implode(" OR ", $stages_array);

            if($stages_query == "")
            {
                $q = Doctrine_Query::create()
                    ->from("Permits a");
                $permits = $q->execute();
            }
            else 
            {
                $q = Doctrine_Query::create()
                    ->from("Permits a")
                    ->where($stages_query);
                $permits = $q->execute();
            }
        }
        else 
        {
            $q = Doctrine_Query::create()
                ->from("Permits a")
                ->orderBy("a.title ASC");
            $permits = $q->execute();
        }

        foreach($permits as $permit)
        {
            $templates[$permit->getId()] =  $permit->getTitle();
        }

        return $templates;
    }
}